// ================================================================
// DENTAL CARE IRELAND - AI RECEPTIONIST BOOKING SYSTEM
// Node: Process, Validate & Prepare all booking data
// ================================================================

// ── Get the incoming webhook body ────────────────────────────────
const inputData = $input.first().json;
const body = inputData.body || inputData;

// ── Extract toolCallId and args from Vapi's nested format ────────
// Vapi wraps tool arguments inside message.toolCallList[0].function.arguments
let args = {};
let toolCallId = 'unknown';
const toolCallList = body?.message?.toolCallList || body?.toolCallList || [];
if (toolCallList.length > 0) {
  const toolCall = toolCallList[0];
  toolCallId = toolCall.id || 'unknown';
  const rawArgs = toolCall?.function?.arguments;
  if (typeof rawArgs === 'string') {
    try { args = JSON.parse(rawArgs); } catch(e) { args = {}; }
  } else if (rawArgs && typeof rawArgs === 'object') {
    args = rawArgs;
  }
} else {
  // Fallback: direct POST body format (used when testing manually)
  args = body;
}

// ── Extract all fields from the Vapi request ─────────────────────
const name    = (args.name    || '').trim();
const phone   = (args.phone   || '').trim();
const email   = (args.email   || '').trim();
const service = (args.service || '').trim();
const date    = (args.date    || '').trim();
const time    = (args.time    || '').trim();

// ── Validate required fields ─────────────────────────────────────
const errors = [];
if (!name)    errors.push('name is required');
if (!phone)   errors.push('phone is required');
if (!email)   errors.push('email is required');
if (!service) errors.push('service is required');
if (!date)    errors.push('date is required');

// ── Format validations ───────────────────────────────────────────
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (email && !emailRegex.test(email)) {
  errors.push('Invalid email format');
}

const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
if (date && !dateRegex.test(date)) {
  errors.push('Date must be in YYYY-MM-DD format (e.g. 2024-03-15)');
}

const phoneRegex = /^[\d\s\+\-\(\)\.]{7,20}$/;
if (phone && !phoneRegex.test(phone)) {
  errors.push('Invalid phone number format');
}

if (time) {
  const timeRegex = /^\d{2}:\d{2}$/;
  if (!timeRegex.test(time)) {
    errors.push('Time must be in HH:MM 24-hour format (e.g. 14:30)');
  }
}

// ── Generate unique Booking ID ───────────────────────────────────
const ts   = Date.now();
const rand = Math.floor(Math.random() * 9000) + 1000;
const bookingId = `DCN-${ts}-${rand}`;

// ── Timestamps (Dublin timezone) ─────────────────────────────────
const now = new Date();
const readableTimestamp = now.toLocaleString('en-IE', { timeZone: 'Europe/Dublin' });
const isoTimestamp      = now.toISOString();

// ── Appointment time handling ─────────────────────────────────────
const appointmentTime = time || '14:00';
const displayTime     = time ? time : '14:00 (default)';

// ── Build calendar start/end datetimes ───────────────────────────
// Parse hours and minutes
const [startHour, startMin] = appointmentTime.split(':').map(Number);
let   endHour = startHour;
let   endMin  = startMin + 30;
if (endMin >= 60) { endHour++; endMin -= 60; }
const endTime = `${String(endHour).padStart(2,'0')}:${String(endMin).padStart(2,'0')}`;

const startDateTime = `${date}T${appointmentTime}:00`;
const endDateTime   = `${date}T${endTime}:00`;

// ── Build HTML email body for patient ────────────────────────────
const patientEmailBody = `
<!DOCTYPE html>
<html>
<body style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto;padding:20px;">
  <div style="background:#1a4d7c;color:white;padding:25px;border-radius:8px 8px 0 0;">
    <h1 style="margin:0;font-size:24px;">&#x1F9B7; Dental Care Ireland</h1>
    <p style="margin:5px 0 0;font-size:14px;">Your appointment is confirmed!</p>
  </div>
  <div style="background:#f8f9fa;padding:25px;border:1px solid #dee2e6;">
    <p>Dear <strong>${name}</strong>,</p>
    <p>Great news! Your appointment at <strong>Dental Care Ireland</strong> has been successfully booked. Here are your details:</p>
    <table style="width:100%;border-collapse:collapse;margin:20px 0;">
      <tr style="background:#e3f0fb;">
        <td style="padding:12px;border:1px solid #ccc;font-weight:bold;width:35%;">&#x1F4C5; Date</td>
        <td style="padding:12px;border:1px solid #ccc;">${date}</td>
      </tr>
      <tr>
        <td style="padding:12px;border:1px solid #ccc;font-weight:bold;">&#x23F0; Time</td>
        <td style="padding:12px;border:1px solid #ccc;">${appointmentTime}</td>
      </tr>
      <tr style="background:#e3f0fb;">
        <td style="padding:12px;border:1px solid #ccc;font-weight:bold;">&#x1F9B7; Service</td>
        <td style="padding:12px;border:1px solid #ccc;">${service}</td>
      </tr>
      <tr>
        <td style="padding:12px;border:1px solid #ccc;font-weight:bold;">&#x1F4CD; Location</td>
        <td style="padding:12px;border:1px solid #ccc;">15 Watergate Street, Navan, Co. Meath, Ireland</td>
      </tr>
      <tr style="background:#e3f0fb;">
        <td style="padding:12px;border:1px solid #ccc;font-weight:bold;">&#x1F516; Booking ID</td>
        <td style="padding:12px;border:1px solid #ccc;font-family:monospace;">${bookingId}</td>
      </tr>
    </table>
    <p>Need to <strong>reschedule or cancel</strong>? Please call us:</p>
    <p style="font-size:20px;color:#1a4d7c;font-weight:bold;">&#x1F4DE; 046 902 1372</p>
    <p style="color:#666;font-size:13px;">Please arrive 5 minutes before your appointment time. We look forward to seeing you!</p>
  </div>
  <div style="background:#1a4d7c;color:white;padding:15px;border-radius:0 0 8px 8px;text-align:center;font-size:13px;">
    <p style="margin:0;">Dental Care Ireland &bull; 15 Watergate Street, Navan, Co. Meath</p>
    <p style="margin:5px 0 0;">Tel: 046 902 1372</p>
  </div>
</body>
</html>`.trim();

// ── Build admin alert email body ──────────────────────────────────
const adminAlertBody = `
<h2 style="color:#c0392b;">&#x1F6A8; Booking System Alert - Action Required</h2>
<p>A patient booking was received but the <strong>Google Calendar event creation FAILED</strong>.</p>
<p><strong>You must manually add this appointment to the calendar and confirm with the patient.</strong></p>
<h3>Patient Details:</h3>
<ul>
  <li><strong>Name:</strong> ${name}</li>
  <li><strong>Phone:</strong> ${phone}</li>
  <li><strong>Email:</strong> ${email}</li>
  <li><strong>Service:</strong> ${service}</li>
  <li><strong>Date:</strong> ${date}</li>
  <li><strong>Time:</strong> ${appointmentTime}</li>
  <li><strong>Booking ID:</strong> ${bookingId}</li>
</ul>
<h3>Timestamp:</h3>
<p>${readableTimestamp}</p>
<hr/>
<p style="color:#666;font-size:12px;">This is an automated alert from the n8n booking system.</p>`.trim();

// ── Pre-build response JSON strings (Vapi expects results array) ──
// Vapi requires: { results: [{ toolCallId, result }] }
const successResponse = JSON.stringify({
  results: [{
    toolCallId,
    result: `Booking confirmed. Your booking ID is ${bookingId}. A confirmation email has been sent to ${email}.`
  }]
});

const errorResponse400 = JSON.stringify({
  results: [{
    toolCallId,
    result: `Booking failed: ${errors.join(', ')}. Please ask the patient to provide all required information.`
  }]
});

const errorResponse500 = JSON.stringify({
  results: [{
    toolCallId,
    result: 'System error - unable to complete the booking. Please tell the patient to call the clinic directly at 046 902 1372.'
  }]
});

// ── Return all processed data ─────────────────────────────────────
return [{
  json: {
    // ── Validation state ──
    valid:           errors.length === 0,
    errors,
    validationError: errors.join(', '),
    toolCallId,

    // ── Patient data ──
    name, phone, email, service,
    date,
    time:         appointmentTime,
    originalTime: time || null,
    displayTime,

    // ── Booking metadata ──
    bookingId,
    isoTimestamp,
    readableTimestamp,
    status: 'Pending',

    // ── Calendar event data ──
    startDateTime,
    endDateTime,
    eventTitle:       `${name} - ${service}`,
    eventDescription: `Phone: ${phone}\nEmail: ${email}\nService: ${service}\nBooking ID: ${bookingId}`,
    eventLocation:    '15 Watergate Street, Navan, Co. Meath, Ireland',

    // ── Email content ──
    emailSubject:      'Appointment Confirmed - Dental Care Ireland',
    patientEmailBody,
    adminAlertBody,
    adminAlertSubject: `\uD83D\uDEA8 Booking System Error - Manual Action Required [${bookingId}]`,

    // ── Pre-built HTTP response bodies ──
    successResponse,
    errorResponse400,
    errorResponse500
  }
}];
